import {onMounted, ref} from 'vue'
import axios from "../plugins/axios";


export default function useEventTypesList() {
    const eventTypeList = ref([])
    const fetchEventTypeList = async () => {
        eventTypeList.value = (await axios.get('/api/info/type')).data
    }
    onMounted(async () => {
        await fetchEventTypeList()
    })

    return {
        eventTypeList
    }
}