                <div v-if="showingParticipantId === participant.id" v-click-away="closeBusyInfo" class="absolute -right-13 bottom-8 p-2 min-w-[320px] rounded-md bg-[#414141] shadow">
                  <div v-for="(e,indx) in participant.events" :key="indx+e.isPrivate">
                    <div class=" text-white">
                      <div v-if="e.isPrivate">
