                      </div>
                      <div v-else class="flex-col">
                        <p class="px-3">
                          {{ `${moment(e.event.startTime).format('HH:mm')} - ${moment(e.event.endTime).format('HH:mm')}` }}
                        </p>
                        <span v-if="participant.events.length > 1">
                          {{ indx+1 }} -
                        </span>
