                      </div>
                    </div>
                  </div>
                </div>
              </button>
            </td>
            <td class="text-center px-3 py-4">
              <div class="relative bg-[#3699FF26] w-8 h-8 rounded-full">
                <Icon icon="mdi:plus" class="text-[#3699FF] cursor-pointer" width="32" @click="selectParticipant(participant)" />
                <div v-if="possibleParticipantOffers.id === participant.id" v-click-away="clearPossibleParticipantOffers" class="absolute right-9 top-0 p-2 min-w-[320px] bg-white rounded-md shadow z-40">
                  <div v-if="possibleParticipantOffers.offers.length">
                    <div v-for="(offer,indx) in possibleParticipantOffers.offers" :key="indx+offer?.id">
                      <div class="text-white">
                        <div class="flex justify-between items-center text-[#1B283F] py-[15px] px-[20px]">
                          <p>
                            {{ `${offer.firstName || ''} ${offer.fatherName || ''} ${offer.lastName || ''}` }}.
                          </p>
                          <div v-if="offer.isBusy" class="">
                            <button class="bg-[#FAEEEE] rounded-full focus:outline-none" @click.prevent>
                              <p class="text-[#D05252] py-[4px] px-[10px]">
                                band
                              </p>
                            </button>
                          </div>
                          <div v-else class="bg-[#3699FF26] w-8 h-8 rounded-full">
                            <Icon icon="mdi:plus" class="text-[#3699FF] cursor-pointer" width="32" @click.stop="selectParticipant(offer,true)" />
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                  <div v-else class="text-[#3699FF]">
                    O'rinbosarlar topilmadi !
                  </div>
                </div>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </section>
    <section v-if="selectedParticipantsList.length" class="section_wrapper rounded-md px-2">
      <table class="min-w-full table-auto text-sm xl:text-md">
        <thead>
          <tr class="bg-white borderedBottom text-[#41424C] font-semibold text-lg">
            <th class="w-20 py-4">
              Т/р
            </th>
            <th class="text-left py-4 pl-3">
              Ижрочилар
            </th>
            <th class="py-4 pl-3">
            </th>
          </tr>
        </thead>
        <tbody>
          <tr
            v-for="(participant, indx) in selectedParticipantsList"
            :key="participant.id"
            class="text-gray-800 borderedBottom rounded-3xl"
          >
            <td class="w-20 py-4">
              <div class="text-center">
                {{ indx + 1 }}
              </div>
            </td>
            <td class="py-4 overflow-hidden overflow-ellipsis ">
              {{ `${participant.lastName || ''} ${participant.firstName || ''} ${participant.fatherName || ''} ` }}
            </td>
            <td>
              <!--       show that this participant is speaker | delete selected speaker Button -->
              <button v-if="participant.id === selectedSpeakerId" class="relative w-8 h-8 rounded-full focus:outline-none" @click.prevent>
<!--                <Icon icon="mdi:microphone" class="text-[#03A600]" width="32" />-->
                <svg xmlns="http://www.w3.org/2000/svg" style="width: 35px; height: 35px" viewBox="0 0 24 24" fill="#03A600" class="w-6 h-6">
                  <path fill-rule="evenodd" d="M2.25 12c0-5.385 4.365-9.75 9.75-9.75s9.75 4.365 9.75 9.75-4.365 9.75-9.75 9.75S2.25 17.385 2.25 12zm13.36-1.814a.75.75 0 10-1.22-.872l-3.236 4.53L9.53 12.22a.75.75 0 00-1.06 1.06l2.25 2.25a.75.75 0 001.14-.094l3.75-5.25z" clip-rule="evenodd" />
                </svg>
                <svg style="width: 20px" xmlns="http://www.w3.org/2000/svg" class="absolute  rounded-full -top-2 -right-2 bg-gray-50 text-red-600 cursor-pointer" viewBox="0 0 24 24" fill="currentColor" @click="deleteSpeakerId">
                  <path fill-rule="evenodd" d="M12 2.25c-5.385 0-9.75 4.365-9.75 9.75s4.365 9.75 9.75 9.75 9.75-4.365 9.75-9.75S17.385 2.25 12 2.25zm-1.72 6.97a.75.75 0 10-1.06 1.06L10.94 12l-1.72 1.72a.75.75 0 101.06 1.06L12 13.06l1.72 1.72a.75.75 0 101.06-1.06L13.06 12l1.72-1.72a.75.75 0 10-1.06-1.06L12 10.94l-1.72-1.72z" clip-rule="evenodd" />
                </svg>
              </button>
              <!--             select speaker Button -->
              <button v-if="!selectedSpeakerId" class="w-8 h-8 rounded-full focus:outline-none" @click="selectSpeaker(participant.id)">
<!--                <Icon icon="mdi:microphone" class="text-[#ABABAB]" width="32" />-->
                <svg style="width: 35px; height: 35px" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="silver" class="w-6 h-6">
                  <path fill-rule="evenodd" d="M2.25 12c0-5.385 4.365-9.75 9.75-9.75s9.75 4.365 9.75 9.75-4.365 9.75-9.75 9.75S2.25 17.385 2.25 12zm13.36-1.814a.75.75 0 10-1.22-.872l-3.236 4.53L9.53 12.22a.75.75 0 00-1.06 1.06l2.25 2.25a.75.75 0 001.14-.094l3.75-5.25z" clip-rule="evenodd" />
