  </div>
</template>

<script setup>
import {defineEmits, defineProps, onMounted, ref, watch, toRefs, defineComponent, reactive} from "vue";
import useOrganizationList from "../hooks/useOrganizationList";
import {useField} from "vee-validate";
import * as yup from "yup";
import useJobDirectionsList from "../hooks/useJobDirectionsList";
import axios from "../plugins/axios";
import moment from "moment";
import ParticipantCard from "./ParticipantCard";
import {Icon} from '@iconify/vue';
defineComponent({ParticipantCard,Icon})
const props = defineProps({
  date:{
    type:[String, Object],
  },
  startTime:{
    type:[String, Object],
  },
  endTime:{
    type:[String, Object],
  },
  resetForm:{
    type:Boolean,
    default:false
  },
  initialParticipants:{
    type:Array,
    default:function (){
      return []
    }
  },
  initialSpeakerId : {
    type:String,
    default:''
  }
})

const {date,startTime,endTime,resetForm} = toRefs(props)

onMounted(()=>{
  if(props.initialParticipants?.length){
    selectedParticipantsList.value = props.initialParticipants
    emit('participants',selectedParticipantsList.value.map(p=>p.id))
  }if(props.initialSpeakerId){
    selectedSpeakerId.value = props.initialSpeakerId
    emit('speakerId', props.initialSpeakerId)
  }
})
const emit = defineEmits(['participants','speakerId'])

const {organizationList} = useOrganizationList()
const {jobDirectionList,fetchJobDirectionListByOrganizationId} = useJobDirectionsList()

const participantsList = ref([])
const selectedParticipantsList = ref([])

const selectedSpeakerId = ref(null)

const showingParticipantId = ref(null)

function setShowingParticipantId(id){
  if(showingParticipantId.value === id){
    closeBusyInfo()
  }else {
    showingParticipantId.value = id
  }
}

function closeBusyInfo(){
  showingParticipantId.value = null
}

const possibleParticipantOffers = reactive({
  id:null,
  offers:null
})



function selectSpeaker(speakerId){
  selectedSpeakerId.value = speakerId
  emit('speakerId',speakerId)
}
function deleteSpeakerId(){
  selectedSpeakerId.value = null
  emit('speakerId',null)
}
async function selectParticipant(participant,isOffer=false){
  if(isOffer){
    possibleParticipantOffers.offers = possibleParticipantOffers.offers.filter((o)=>o.id !== participant.id )
    participantsList.value = participantsList.value.filter((p)=>p.id !== participant.id)
    selectedParticipantsList.value.push(participant)
    emit('participants',selectedParticipantsList.value.map(p=>p.id))
  }else if(!isOffer && participant?.isBusy){
    const resp =  (await axios.get(`/api/user/offer/${participant.id}`,{
      params:{
        date:date.value.length < 11 ?  date.value :  moment(date.value).format('YYYY-MM-DD'),
        startTime :startTime.value.length < 6 ?  startTime.value :  moment(startTime.value).format('HH:mm'),
        endTime:startTime.value.length < 6 ?  startTime.value :  moment(startTime.value).format('HH:mm')
      }
    })).data?.data
    const participantIds = selectedParticipantsList.value.map((p)=>p.id)
    possibleParticipantOffers.id = participant.id;
    possibleParticipantOffers.offers = resp.filter((offer)=>!participantIds.includes(offer.id))
  }else{
    participantsList.value = participantsList.value.filter((p)=>p.id !== participant.id )
    selectedParticipantsList.value.push(participant)
    emit('participants',selectedParticipantsList.value.map(p=>p.id))
  }
}

function clearPossibleParticipantOffers(e){
  e.stopPropagation()
  console.log(e)
  possibleParticipantOffers.id = null
  possibleParticipantOffers.offers = null
}

const validatorMessageGenerator = ({path}) => {
  return `Ушбу майдон тўлдирилиши шарт`;
};

const {
  value: organId,
} = useField('organId', yup.string(), {initialValue: ''});
const {
  value: directionId,
} = useField('directionId', yup.string(), {initialValue: ''});
const {
  value: search,
} = useField('search', yup.string(), {initialValue: ''});


function filterParticipants(participants){
  if(selectedParticipantsList.value.length){
    const existParticipantIds = selectedParticipantsList.value.map((p)=>p.id)
    return participants.filter((p)=>!existParticipantIds.includes(p.id))
  }
  else return participants
}

function deleteSelectedParticipant(participantId){
  if(selectedSpeakerId.value === participantId){
    selectedSpeakerId.value = null
  }
  selectedParticipantsList.value = selectedParticipantsList.value.filter(p => p.id !==participantId)
  emit('participants',selectedParticipantsList.value)
  fetchParticipants()
}

async function fetchParticipants(){
  if(date && startTime && endTime && organId.value){
    let participantsFromServer =  ((await axios.get('/api/user/participant',{
      params:{
        date: date.value.length < 11 ?  date.value :  moment(date.value).format('YYYY-MM-DD'),
        endTime: endTime.value.length < 6 ?  endTime.value : moment(endTime.value).format('HH:mm'),
        startTime: startTime.value.length < 6 ?  startTime.value :  moment(startTime.value).format('HH:mm'),
        organId:organId.value,
        directionId:directionId.value,
        search:search.value,
      }
    })).data)?.data
    participantsList.value = filterParticipants(participantsFromServer)
  }
}

watch([date,startTime,endTime,organId,directionId,search],async ([date,startTime,endTime,organId])=>{
  await fetchParticipants()
})

watch(()=>resetForm.value,(resetFormValue)=>{
  if(resetFormValue){
    participantsList.value= []
    selectedSpeakerId.value= null
    selectedParticipantsList.value= []
    showingParticipantId.value= null
    possibleParticipantOffers.id = null
    possibleParticipantOffers.offers = null
    directionId.value=''
    organId.value=''
    search.value=''
  }
})

</script>

