<template>
  <form class="pl-4" @submit="onSubmit">
    <div class="grid grid-cols-2 md:grid-cols-3 gap-4 2xl:w-[90%]">
      <div class="form_wrapper my-1">
        <label class="input_label" for="fullName">
          Ф.И.Ш
        </label>
        <input id="fullName" v-model="fullName" class="base_input" placeholder="Ф.И.Ш" name="fullName" type="text">
        <span>{{ fullNameError }}</span>
      </div>
      <div class="form_wrapper my-1">
        <label class="input_label" for="organisationName">
          Ташкилот номи
        </label>
        <input id="organisationName" v-model="organisationName" class="base_input" placeholder="Ташкилот номи  nomi" name="organisationName" type="text">
        <span>{{ organisationNameError }}</span>
      </div>
      <div class="form_wrapper my-1">
        <label class="input_label" for="position">
          Лавозими
        </label>
        <input id="position" v-model="position" class="base_input" placeholder="Лавозими" name="position" type="text">
        <span>{{ positionError }}</span>
      </div>
      <div class="col-span-2 md:col-span-3">
        <div class="flex justify-end">
          <button type="submit" class="p-2 bg-[#D9EBFC] rounded-full text-primary flex items-center justify-center focus:outline-none" :disabled="isSubmitting">
            <Icon icon="mdi:account-multiple-plus" width="32" class="text-primary mx-2" />
            Қўшимча ижрочи қўшиш
          </button>
        </div>
      </div>
    </div>
  </form>
  <section class="section_wrapper rounded-md p-4">
    <table class="min-w-full table-auto text-sm xl:text-md">
      <thead>
        <tr class="bg-white border-b border-gray-300 text-gray-400">
          <th class="w-20 py-4 pl-3">
            Т/р
          </th>
          <th class="text-left py-4 pl-3">
            Қўшимча ижрочилар
          </th>
          <th class="text-left py-4 pl-3">
            Лавозими
          </th>
          <th class="text-left py-4 pl-3">
            Ташкилоти
          </th>
          <th class="py-4 pl-3">
          </th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="(v ,indx ) in createdVisitors" :key="v.id" class="text-gray-800 odd:bg-white even:bg-grayPrimary rounded-3xl">
          <td class="w-20 py-4 pl-3">
            <div class="text-center">
              {{ indx + 1 }}
            </div>
          </td>
          <td class="py-4 pl-3 overflow-hidden overflow-ellipsis ">
            {{ v.fullName }}
          </td>
          <td class="py-4 pl-3 overflow-hidden overflow-ellipsis ">
            {{ v.position }}
          </td>
          <td class="py-4 pl-3 overflow-hidden overflow-ellipsis ">
            {{ v.organisationName }}
          </td>
          <td class="text-center px-3 py-4">
            <Icon icon="mdi:minus-circle" class="text-red-600 cursor-pointer" width="32" @click="deleteVisitor(v.id)" />
          </td>
        </tr>
      </tbody>
    </table>
  </section>
</template>

<script setup>
import {useField, useForm} from 'vee-validate';
import * as yup from 'yup';
import {defineComponent, defineProps, onMounted, ref, toRefs, watch} from "vue";
import VisitorCard from "./VisitorCard";
import { Icon } from '@iconify/vue';
defineComponent({Icon,VisitorCard})
const emit = defineEmits(['visitor-create'])
const {handleSubmit, isSubmitting, resetForm} = useForm();

const props = defineProps({
  resetVisitorsForm:{
    type:Boolean,
    default:false
  },
  initialVisitors:{
    type:[Array],
    default:function (){
      return []
    }
  }
})
const {resetVisitorsForm} = toRefs(props)


const validatorMessageGenerator = ({path}) => {
  return `Ушбу майдон тўлдирилиши шарт`;
};

const createdVisitors = ref([])

onMounted(()=>{
  if(props.initialVisitors?.length){
    createdVisitors.value = props.initialVisitors
  }
})

function onInvalidSubmit({values, errors, results}) {
  console.log(errors)
}
function deleteVisitor(visitorId){
  createdVisitors.value = createdVisitors.value.filter(v=>v.id !== visitorId)
}

const onSubmit  = handleSubmit((values)=>{
  createdVisitors.value.push({...values,id:Date.now()})
  const emitableList = createdVisitors.value.map(l=>{
    let obj = {...l}
    delete obj['id']
    return obj
  })
  emit('visitor-create',emitableList)
  resetForm()
},onInvalidSubmit)


watch(()=>resetVisitorsForm.value,(resetFormValue)=>{
  if(resetFormValue){
    createdVisitors.value=[]
  }
})


const {
  value: fullName,
  errorMessage: fullNameError
} = useField('fullName', yup.string().required(validatorMessageGenerator), {initialValue: ''});

const {
  value: organisationName,
  errorMessage: organisationNameError
} = useField('organisationName', yup.string().required(validatorMessageGenerator), {initialValue: ''});

const {
  value: position,
  errorMessage: positionError
} = useField('position', yup.string().required(validatorMessageGenerator), {initialValue: ''});
</script>

<style scoped>
span {
  --tw-text-opacity: 1;
  color: rgba(220, 38, 38, var(--tw-text-opacity));
}
</style>