import {onMounted, ref} from 'vue'
import axios from "../plugins/axios";


export default function useSphereList() {
    const sphereList = ref([])
    const fetchSphereList = async () => {
        sphereList.value = (await axios.get('/api/info/sphere')).data
    }
    onMounted(async () => {
        await fetchSphereList()
    })

    return {
        sphereList
    }
}