<template>
  <div class="flex justify-around shadow border rounded w-full p-1 box-border base_input border-none">
    <button
      v-for="item in titles"
      :key="item.title"
      :style="`width: ${(100/$props.titles.length)-1}%`"
      class="text-center text-sm py-1 h-full box-border rounded"
      :class="{'bg-primary text-white' : item.title===activeBtnTitle , 'text-gray-900 bg-white':item.title!==activeBtnTitle}"
      @click.prevent="setItem(item)"
    >
      {{ item.title }}
    </button>
  </div>
</template>

<script>
export default {
  name: 'ButtonGroup',
  props: {
    titles: Array,
    selectedItem: [Object,Boolean,String]
  },
  emits: ['update:selected-item'],
  data() {
    return {
      activeBtnTitle: '',
    };
  },
  created() {
    this.setItem(this.$props.titles.filter(t=>t.type === this.$props.selectedItem)[0])
  },
  methods: {
    setItem(item) {
      this.activeBtnTitle = item.title;
      this.$emit('update:selected-item', item.type);
    },
  }
};
</script>

