async function watchRouteId(){
  if(route?.params?.id && !isEventEditMode.value){
    if(route?.params?.id){
      const preEventData = (await axios.get(`/api/pre-event/${route.params.id}`))?.data?.data
      if(preEventData){
        title.value = preEventData.title
        date.value  = new Date(preEventData.date)
        startTime.value  = new Date(null,null,null,moment(preEventData.startTime).format('hh'),moment(preEventData.startTime).format('mm'))
        endTime.value  = new Date(null,null,null,moment(preEventData.endTime).format('hh'),moment(preEventData.startTime).format('mm'))
      }
    }
  }
}

