}
async function deleteEvent(){
  try {
    const resp =  (await axios.delete(`/api/event/${editableEventId.value}`)).data
    await store.dispatch('toast',{
      type:'success',
      message:resp.message
    })
    modalComponentRef.value.closeModal()
    router.push('/')
  }catch (e) {
    await store.dispatch('errorHandler',e)
  }
}

