  console.log(fieldsFromServer)
  title.value = fieldsFromServer.title
  date.value = new Date(fieldsFromServer.date)
  startTime.value = new Date(null,null,null,moment(fieldsFromServer.startTime).format('HH'))
  endTime.value = new Date(null,null,null,moment(fieldsFromServer.endTime).format('HH'))
