  try {
  const payloadObj = {
    date: date?.length < 11 ?  date :  moment(date).format('YYYY-MM-DD'),
    endTime: endTime?.length < 6 ?  endTime : moment(endTime).format('HH:mm'),
    startTime: startTime?.length < 6 ?  startTime :  moment(startTime).format('HH:mm'),
    ...values,
  }
  if( isEventEditMode.value ){
      const deletedFileIdsList = deletedInitialFileIds.value
      payloadObj.deletedFileIds = deletedFileIdsList
      payloadObj.fileIds = []
      // payloadObj.fileIds = initialFiles.value.map((f)=>{
      //   if( deletedFileIdsList.length && !deletedFileIdsList.includes(f.id) ){
      //     return f.id
      //   }
      // })
      for(let indx in initialFiles.value){
        if(!deletedFileIdsList.includes(initialFiles.value[indx].id)){
          payloadObj.fileIds = [...payloadObj.fileIds,initialFiles.value[indx].id]
        }
      }

      if(initialParticipants.value.length){

      }
    }
  const formData = new FormData();
  const blob = new Blob([JSON.stringify(payloadObj, null, 2)], { type: 'application/json' });
  formData.append('dto',blob)
  upldFiles.value.forEach(f=>{
    formData.append('files',f)
  })
  let resp ;
  if( isEventEditMode.value ){
    resp = (await axios.put(`/api/event/${editableEventId.value}`, formData)).data
  } else {
    resp = (await axios.post('/api/event', formData)).data
  }

  fullyResetForm()
  modalComponentRef.value.openModal()
  await store.dispatch('toast',{
    type:'success',
    message:resp?.message
  })
} catch (e) {
  await store.dispatch('errorHandler', e)
}
},onInvalidSubmit)

